package main.rice.basegen;

import main.rice.node.APyNode;
import main.rice.obj.APyObj;
import main.rice.test.TestCase;
import java.util.*;

/**
 * Generates test cases by combining values from multiple argument nodes.
 * Supports both exhaustive generation (Cartesian product of all exhaustive values)
 * and random generation (random samples that don't overlap with exhaustive tests).
 */
public class BaseSetGenerator {

    /**
     * The argument nodes for test generation.
     */
    private final List<APyNode<?>> nodes;

    /**
     * The number of random tests to generate.
     */
    private final int numRand;

    /**
     * The set of all test cases generated so far (used to prevent duplicates).
     */
    private final Set<TestCase> currentTests;

    /**
     * Constructor for a BaseSetGenerator.
     *
     * @param nodes   the argument nodes
     * @param numRand the number of random tests to generate
     */
    public BaseSetGenerator(List<APyNode<?>> nodes, int numRand) {
        this.nodes = nodes;
        this.numRand = numRand;
        this.currentTests = new HashSet<>();
    }

    /**
     * Generates all exhaustive test cases by computing the Cartesian product
     * of each node's exhaustive values.
     *
     * @return the set of all exhaustive test cases
     */
    public Set<TestCase> genExTests() {
        List<Set<? extends APyObj>> allExVals = new ArrayList<>();
        for (APyNode<?> node : this.nodes) {
            allExVals.add(node.genExVals());
        }

        Set<TestCase> result = new HashSet<>();
        cartesianProduct(allExVals, 0, new ArrayList<>(), result);
        this.currentTests.addAll(result);
        return result;
    }

    /**
     * Helper method to compute the Cartesian product of multiple sets of values.
     */
    private void cartesianProduct(List<Set<? extends APyObj>> allExVals, int idx,
            List<APyObj> current, Set<TestCase> result) {
        if (idx == allExVals.size()) {
            result.add(new TestCase(new ArrayList<>(current)));
            return;
        }
        for (APyObj val : allExVals.get(idx)) {
            current.add(val);
            cartesianProduct(allExVals, idx + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    /**
     * Generates random test cases that don't overlap with previously generated
     * (exhaustive) test cases.
     *
     * @return the set of random test cases
     */
    public Set<TestCase> genRandTests() {
        Set<TestCase> result = new HashSet<>();
        int maxAttempts = this.numRand * 100;
        int attempts = 0;

        while (result.size() < this.numRand && attempts < maxAttempts) {
            List<APyObj> args = new ArrayList<>();
            for (APyNode<?> node : this.nodes) {
                args.add(node.genRandVal());
            }
            TestCase tc = new TestCase(args);
            if (!this.currentTests.contains(tc)) {
                result.add(tc);
            }
            attempts++;
        }

        this.currentTests.addAll(result);
        return result;
    }

    /**
     * Generates the complete base set: all exhaustive tests plus the specified
     * number of random tests (avoiding duplicates).
     *
     * @return the combined list of test cases
     */
    public List<TestCase> genBaseSet() {
        Set<TestCase> exTests = genExTests();
        Set<TestCase> randTests = genRandTests();

        List<TestCase> result = new ArrayList<>(exTests);
        result.addAll(randTests);
        return result;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;

/**
 * An abstract class for nodes that generate iterable Python objects (lists, tuples,
 * sets, strings). The exhaustive and random domains represent lengths of the
 * generated iterables.
 *
 * @param <InnerType> the type of elements within the iterable
 * @param <ObjType>   the type of iterable Python object generated
 */
public abstract class AIterablePyNode<InnerType extends APyObj, ObjType extends APyObj>
        extends APyNode<ObjType> {

    /**
     * The child node used to generate elements for this iterable.
     */
    protected APyNode<InnerType> leftChild;

    /**
     * Constructor for an AIterablePyNode.
     *
     * @param leftChild the child node for generating elements
     */
    public AIterablePyNode(APyNode<InnerType> leftChild) {
        this.leftChild = leftChild;
    }

    @Override
    public APyNode<InnerType> getLeftChild() {
        return this.leftChild;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import java.util.List;
import java.util.Set;

/**
 * An abstract class whose subclasses represent domains of possible values for a
 * single Python type.
 *
 * @param <ObjType> the type of Python object generated by this node
 */
public abstract class APyNode<ObjType extends APyObj> {

    /**
     * The exhaustive domain for this node, representing the set of values (or lengths)
     * to be used for exhaustive test generation.
     */
    protected List<Integer> exDomain;

    /**
     * The random domain for this node, representing the set of values (or lengths)
     * to be used for random test generation.
     */
    protected List<Integer> ranDomain;

    /**
     * Returns the exhaustive domain for this node.
     *
     * @return the exhaustive domain
     */
    public List<Integer> getExDomain() {
        return this.exDomain;
    }

    /**
     * Sets the exhaustive domain for this node.
     *
     * @param exDomain the exhaustive domain
     */
    public void setExDomain(List<Integer> exDomain) {
        this.exDomain = exDomain;
    }

    /**
     * Returns the random domain for this node.
     *
     * @return the random domain
     */
    public List<Integer> getRanDomain() {
        return this.ranDomain;
    }

    /**
     * Sets the random domain for this node.
     *
     * @param ranDomain the random domain
     */
    public void setRanDomain(List<Integer> ranDomain) {
        this.ranDomain = ranDomain;
    }

    /**
     * Returns the left child of this node, or null if there is none.
     *
     * @return the left child node
     */
    public abstract APyNode<?> getLeftChild();

    /**
     * Returns the right child of this node, or null if there is none.
     *
     * @return the right child node
     */
    public abstract APyNode<?> getRightChild();

    /**
     * Generates all values in the exhaustive domain.
     *
     * @return a set of all exhaustive values
     */
    public abstract Set<ObjType> genExVals();

    /**
     * Generates a single random value from the random domain.
     *
     * @return a random value
     */
    public abstract ObjType genRandVal();
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node for generating Python dictionary values. Has both a left child
 * (key generator) and a right child (value generator). The exhaustive and
 * random domains represent the possible sizes of the generated dictionaries.
 * Dictionaries have unique keys.
 *
 * @param <KeyType> the type of keys in the dictionary
 * @param <ValType> the type of values in the dictionary
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    private final APyNode<KeyType> leftChild;
    private final APyNode<ValType> rightChild;
    private final Random random = new Random();

    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValType> valNode) {
        this.leftChild = keyNode;
        this.rightChild = valNode;
    }

    @Override
    public APyNode<KeyType> getLeftChild() {
        return this.leftChild;
    }

    @Override
    public APyNode<ValType> getRightChild() {
        return this.rightChild;
    }

    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<KeyType> keySet = this.leftChild.genExVals();
        Set<ValType> valSet = this.rightChild.genExVals();
        List<KeyType> keys = new ArrayList<>(keySet);
        List<ValType> vals = new ArrayList<>(valSet);

        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();

        for (int size : this.exDomain) {
            if (size == 0) {
                result.add(new PyDictObj<>(new HashMap<>()));
            } else {
                // Generate all combinations of `size` keys (unique keys)
                List<List<KeyType>> keyCombos = allCombinations(keys, size);

                for (List<KeyType> keyCombo : keyCombos) {
                    // For each key combination, generate all value assignments
                    List<List<ValType>> valSequences = allSequences(vals, size);
                    for (List<ValType> valSeq : valSequences) {
                        Map<KeyType, ValType> map = new HashMap<>();
                        for (int i = 0; i < size; i++) {
                            map.put(keyCombo.get(i), valSeq.get(i));
                        }
                        result.add(new PyDictObj<>(map));
                    }
                }
            }
        }
        return result;
    }

    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int size = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        Map<KeyType, ValType> map = new HashMap<>();
        int maxAttempts = size * 100;
        int attempts = 0;
        while (map.size() < size && attempts < maxAttempts) {
            KeyType key = this.leftChild.genRandVal();
            if (!map.containsKey(key)) {
                ValType val = this.rightChild.genRandVal();
                map.put(key, val);
            }
            attempts++;
        }
        return new PyDictObj<>(map);
    }

    private static <T> List<List<T>> allCombinations(List<T> elements, int k) {
        List<List<T>> result = new ArrayList<>();
        allCombinationsHelper(elements, k, 0, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allCombinationsHelper(List<T> elements, int k, int start,
            List<T> current, List<List<T>> result) {
        if (current.size() == k) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = start; i < elements.size(); i++) {
            current.add(elements.get(i));
            allCombinationsHelper(elements, k, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    private static <T> List<List<T>> allSequences(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        allSequencesHelper(elements, length, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allSequencesHelper(List<T> elements, int length,
            List<T> current, List<List<T>> result) {
        if (current.size() == length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            allSequencesHelper(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.PyIntObj;
import java.util.*;

/**
 * A node for generating Python int values. The exhaustive and random domains
 * contain the actual integer values to be used.
 */
public class PyIntNode extends APyNode<PyIntObj> {

    private final Random random = new Random();

    @Override
    public APyNode<?> getLeftChild() {
        return null;
    }

    @Override
    public APyNode<?> getRightChild() {
        return null;
    }

    @Override
    public Set<PyIntObj> genExVals() {
        Set<PyIntObj> result = new HashSet<>();
        for (Integer val : this.exDomain) {
            result.add(new PyIntObj(val));
        }
        return result;
    }

    @Override
    public PyIntObj genRandVal() {
        return new PyIntObj(this.ranDomain.get(this.random.nextInt(this.ranDomain.size())));
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyListObj;
import java.util.*;

/**
 * A node for generating Python list values. The exhaustive and random domains
 * represent the possible lengths of the generated lists.
 *
 * @param <InnerType> the type of elements within the list
 */
public class PyListNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PyListObj<InnerType>> {

    private final Random random = new Random();

    public PyListNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    @Override
    public Set<PyListObj<InnerType>> genExVals() {
        Set<InnerType> elemSet = this.leftChild.genExVals();
        List<InnerType> elems = new ArrayList<>(elemSet);
        Set<PyListObj<InnerType>> result = new HashSet<>();

        for (int length : this.exDomain) {
            if (length == 0) {
                result.add(new PyListObj<>(new ArrayList<>()));
            } else {
                List<List<InnerType>> sequences = allSequences(elems, length);
                for (List<InnerType> seq : sequences) {
                    result.add(new PyListObj<>(new ArrayList<>(seq)));
                }
            }
        }
        return result;
    }

    @Override
    public PyListObj<InnerType> genRandVal() {
        int length = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        List<InnerType> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(this.leftChild.genRandVal());
        }
        return new PyListObj<>(elements);
    }

    private static <T> List<List<T>> allSequences(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        allSequencesHelper(elements, length, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allSequencesHelper(List<T> elements, int length,
            List<T> current, List<List<T>> result) {
        if (current.size() == length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            allSequencesHelper(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PySetObj;
import java.util.*;

/**
 * A node for generating Python set values. The exhaustive and random domains
 * represent the possible sizes of the generated sets. Sets do not allow
 * duplicate elements.
 *
 * @param <InnerType> the type of elements within the set
 */
public class PySetNode<InnerType extends APyObj>
        extends AIterablePyNode<InnerType, PySetObj<InnerType>> {

    private final Random random = new Random();

    public PySetNode(APyNode<InnerType> leftChild) {
        super(leftChild);
    }

    @Override
    public Set<PySetObj<InnerType>> genExVals() {
        Set<InnerType> elemSet = this.leftChild.genExVals();
        List<InnerType> elems = new ArrayList<>(elemSet);
        Set<PySetObj<InnerType>> result = new HashSet<>();

        for (int size : this.exDomain) {
            if (size == 0) {
                result.add(new PySetObj<>(new HashSet<>()));
            } else {
                List<List<InnerType>> combos = allCombinations(elems, size);
                for (List<InnerType> combo : combos) {
                    result.add(new PySetObj<>(new HashSet<>(combo)));
                }
            }
        }
        return result;
    }

    @Override
    public PySetObj<InnerType> genRandVal() {
        int size = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        Set<InnerType> elements = new HashSet<>();
        int maxAttempts = size * 100;
        int attempts = 0;
        while (elements.size() < size && attempts < maxAttempts) {
            elements.add(this.leftChild.genRandVal());
            attempts++;
        }
        return new PySetObj<>(elements);
    }

    private static <T> List<List<T>> allCombinations(List<T> elements, int k) {
        List<List<T>> result = new ArrayList<>();
        allCombinationsHelper(elements, k, 0, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allCombinationsHelper(List<T> elements, int k, int start,
            List<T> current, List<List<T>> result) {
        if (current.size() == k) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = start; i < elements.size(); i++) {
            current.add(elements.get(i));
            allCombinationsHelper(elements, k, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.PyCharObj;
import main.rice.obj.PyStringObj;
import java.util.*;

/**
 * A node for generating Python string values. Unlike other iterable nodes,
 * PyStringNode takes a String of allowed characters in its constructor
 * rather than a child node. The exhaustive and random domains represent
 * the possible lengths of the generated strings.
 */
public class PyStringNode extends AIterablePyNode<PyCharObj, PyStringObj> {

    private final String chars;
    private final Random random = new Random();

    public PyStringNode(String chars) {
        super(null);
        this.chars = chars;
    }

    @Override
    public APyNode<PyCharObj> getLeftChild() {
        return null;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        List<PyCharObj> charList = new ArrayList<>();
        for (int i = 0; i < this.chars.length(); i++) {
            charList.add(new PyCharObj(this.chars.charAt(i)));
        }

        Set<PyStringObj> result = new HashSet<>();
        for (int length : this.exDomain) {
            if (length == 0) {
                result.add(new PyStringObj(""));
            } else {
                List<List<PyCharObj>> sequences = allSequences(charList, length);
                for (List<PyCharObj> seq : sequences) {
                    result.add(new PyStringObj(seq));
                }
            }
        }
        return result;
    }

    @Override
    public PyStringObj genRandVal() {
        int length = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        List<PyCharObj> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(new PyCharObj(this.chars.charAt(
                    this.random.nextInt(this.chars.length()))));
        }
        return new PyStringObj(elements);
    }

    private static <T> List<List<T>> allSequences(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        allSequencesHelper(elements, length, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allSequencesHelper(List<T> elements, int length,
            List<T> current, List<List<T>> result) {
        if (current.size() == length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            allSequencesHelper(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

