package main.rice.test;

import main.rice.obj.APyObj;
import java.util.ArrayList;
import java.util.List;

/**
 * A representation of a single test case, consisting of a list of arguments
 * (Python objects) to be passed to a function under test.
 */
public class TestCase {

    /**
     * The arguments for this test case.
     */
    private final List<APyObj> args;

    /**
     * Constructor for a TestCase; initializes its args to the input.
     *
     * @param args the arguments for this test case
     */
    public TestCase(List<? extends APyObj> args) {
        this.args = new ArrayList<>(args);
    }

    /**
     * Returns the arguments for this test case.
     *
     * @return the arguments
     */
    public List<APyObj> getArgs() {
        return this.args;
    }

    /**
     * Compares this test case to the input object by value.
     *
     * @param obj the object to compare against
     * @return true if equivalent by value
     */
    @Override
    public boolean equals(Object obj) {
        if (!(obj instanceof TestCase other)) {
            return false;
        }
        return this.args.equals(other.args);
    }

    /**
     * Computes a hash code based on the arguments.
     *
     * @return the hash code
     */
    @Override
    public int hashCode() {
        return this.args.hashCode();
    }

    /**
     * Returns a string representation of this test case.
     *
     * @return a string representation
     */
    @Override
    public String toString() {
        return this.args.toString();
    }
}

